// T212 SubscriptionAnalyticsAggregator — additive-subtractive MRR

// ✅ CORRECT: two event handlers
@EventPattern('SubscriptionActivated')
async onActivated(event: Record<string, unknown>) {
  const mrr = this.normalizeMrr(event);
  await this.updateMrr(tenantId, +mrr); // add
}

@EventPattern('SubscriptionCancelled')
async onCancelled(event: Record<string, unknown>) {
  const mrr = this.normalizeMrr(event);
  await this.updateMrr(tenantId, -mrr); // subtract
}

private normalizeMrr(event: Record<string, unknown>): number {
  const priceCents = event['priceCents'] as number;
  const interval = event['billingInterval'] as string;
  // MACHINE formula — NOT configurable
  if (interval === 'ANNUAL') return Math.floor(priceCents / 12);
  if (interval === 'CUSTOM') {
    const intervalDays = event['intervalDays'] as number;
    return Math.floor(priceCents / intervalDays * 30);
  }
  return priceCents; // MONTHLY: no normalization needed
}

